"use client";
import { useState, useEffect, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Plus, Edit, Trash2, Music, PlayCircle, Loader2, ImageIcon } from "lucide-react";
import { useAuth } from "@/components/auth-provider";
import { MusicFormModal } from "./music-form-modal";
import { MusicDetailModal } from "./music-detail-modal";
import { useToast } from "@/hooks/use-toast";
import { Card, CardContent } from "@/components/ui/card";
import Image from "next/image";

export default function MusicBoardList() {
  const [posts, setPosts] = useState<any[]>([]);
  const [isFormModalOpen, setIsFormModalOpen] = useState(false);
  const [selectedPost, setSelectedPost] = useState<any | null>(null);
  const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const { hasPermission } = useAuth();
  const { toast } = useToast();

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    try {
      const response = await fetch("/api/posts?category=board&subcategory=music");
      if (response.ok) {
        const data = await response.json();
        setPosts(data);
      }
    } catch (error) {
      console.error("Failed to fetch posts:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchPosts();
  }, [fetchPosts]);

  const handlePostClick = (post: any) => {
    setSelectedPost(post);
    setIsDetailModalOpen(true);
  };

  const handlePostCreated = () => {
    fetchPosts();
  };

  const handlePostUpdated = () => {
    fetchPosts();
    setIsDetailModalOpen(false);
  };

  const handlePostDeleted = () => {
    fetchPosts();
    setIsDetailModalOpen(false);
  };

  const formatDate = (dateString: string) => {
    if (!dateString) return "";
    const date = new Date(dateString);
    return new Intl.DateTimeFormat("ko-KR", {
      year: "numeric",
      month: "long",
      day: "numeric",
    }).format(date);
  };

  if (isLoading) {
    return (
      <div className="flex bg-card/60 backdrop-blur-sm border-0 justify-center items-center h-64">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        {hasPermission(["SUPER_ADMIN"]) && (
          <Button onClick={() => setIsFormModalOpen(true)} className="gap-2">
            <Plus className="h-4 w-4" />새 게시물
          </Button>
        )}
      </div>

      {posts.length === 0 ? (
        <Card className="p-12 text-center bg-card/60 backdrop-blur-sm border-0">
          <div className="flex flex-col items-center gap-4 text-muted-foreground">
            <Music className="h-12 w-12" />
            <p>등록된 음악이 없습니다.</p>
          </div>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {posts.map((post) => {
            let embedUrl = post.video_url || "";
            if (embedUrl.includes("youtube.com") || embedUrl.includes("youtu.be")) {
              embedUrl = embedUrl.replace("watch?v=", "embed/").replace("youtu.be/", "youtube.com/embed/").split("&")[0].split("?si=")[0];
            }
            return (
              <Card 
                key={post.id} 
                className="overflow-hidden bg-card/60 backdrop-blur-sm border shadow-sm relative cursor-pointer hover:border-primary transition-colors block"
                onClick={() => handlePostClick(post)}
              >
                <CardContent className="p-0 flex flex-col h-full">
                  <div className="aspect-video w-full relative bg-muted flex flex-col items-center justify-center overflow-hidden">
                    {post.thumbnail_url ? (
                      <Image 
                        src={post.thumbnail_url} 
                        alt={post.title}
                        fill
                        className="object-cover"
                      />
                    ) : post.video_url ? (
                      <>
                        {(post.video_type === "youtube" || post.video_url.includes("youtube.com") || post.video_url.includes("youtu.be")) ? (
                          <iframe 
                            src={embedUrl} 
                            className="w-full h-full pointer-events-none" 
                            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                            allowFullScreen 
                            tabIndex={-1}
                          />
                        ) : (
                          <video src={post.video_url} className="w-full h-full object-cover pointer-events-none" />
                        )}
                        <div className="absolute inset-0 bg-black/50 p-4 flex flex-col justify-end pointer-events-none">
                           <h3 className="text-lg font-bold text-white line-clamp-2">{post.title}</h3>
                           {post.content && (
                             <p className="text-sm text-white/80 line-clamp-2 mt-1">{post.content}</p>
                           )}
                        </div>
                      </>
                    ) : (
                      <div className="w-full h-full flex flex-col items-center justify-center text-center space-y-2 p-4">
                         <h3 className="text-lg font-bold text-foreground line-clamp-2">{post.title}</h3>
                         {post.content && (
                           <p className="text-sm text-muted-foreground line-clamp-3">{post.content}</p>
                         )}
                      </div>
                    )}
                  </div>
                  
                  <div className="p-4 flex flex-col gap-2 relative bg-card flex-1">
                    {hasPermission(["SUPER_ADMIN"]) && (
                      <div className="absolute top-4 right-4 z-10">
                          <Button variant="ghost" size="sm" onClick={(e) => { e.stopPropagation(); handlePostClick(post); }}>
                            관리
                          </Button>
                      </div>
                    )}
                    {post.thumbnail_url && (
                        <h3 className="text-lg font-semibold text-foreground pr-12 truncate">{post.title}</h3>
                    )}
                    <p className="text-xs text-muted-foreground">등록일: {formatDate(post.created_at)}</p>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {selectedPost && (
        <MusicDetailModal
          open={isDetailModalOpen}
          onOpenChange={(open) => {
            setIsDetailModalOpen(open);
            if (!open) {
              setTimeout(() => setSelectedPost(null), 300);
            }
          }}
          post={selectedPost}
          onDelete={handlePostDeleted}
        />
      )}

      <MusicFormModal
        open={isFormModalOpen}
        onOpenChange={(open) => setIsFormModalOpen(open)}
        onSuccess={handlePostCreated}
      />
    </div>
  );
}