'use client';

import { useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Upload, X, Plus, Link, Video } from 'lucide-react';
import { toast } from 'sonner';
import Image from 'next/image';

interface MusicFormModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess: () => void;
}

interface ImagePreview {
  file: File;
  preview: string;
}

export function MusicFormModal({
  open,
  onOpenChange,
  onSuccess,
}: MusicFormModalProps) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [images, setImages] = useState<ImagePreview[]>([]);
  const [videoType, setVideoType] = useState<'link' | 'upload'>('link');
  const [videoUrl, setVideoUrl] = useState('');
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    
    files.forEach((file) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImages((prev) => [...prev, { file, preview: reader.result as string }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleRemoveImage = (index: number) => {
    setImages((prev) => prev.filter((_, i) => i !== index));
  };

  const handleVideoFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setVideoFile(file);
    }
  };

  const getYouTubeEmbedUrl = (url: string): string | null => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    if (match && match[2].length === 11) {
      return `https://www.youtube.com/embed/${match[2]}`;
    }
    return null;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!title.trim()) {
      toast.error('제목을 입력해주세요.');
      return;
    }

    setIsLoading(true);

    try {
      const formData = new FormData();
      formData.append('category', 'board');
      formData.append('subcategory', 'music');
      formData.append('title', title);
      formData.append('content', content);
      
      images.forEach((img) => {
        formData.append('images', img.file);
      });

      if (videoType === 'link' && videoUrl) {
        const embedUrl = getYouTubeEmbedUrl(videoUrl);
        if (embedUrl) {
          formData.append('videoUrl', embedUrl);
          formData.append('videoType', 'youtube');
        } else {
          formData.append('videoUrl', videoUrl);
          formData.append('videoType', 'link');
        }
      } else if (videoType === 'upload' && videoFile) {
        // For video upload, we would need additional handling
        // For now, we'll store the video as a regular file
        formData.append('video', videoFile);
        formData.append('videoType', 'upload');
      }

      const res = await fetch('/api/posts', {
        method: 'POST',
        body: formData,
      });

      if (res.ok) {
        toast.success('음악이 등록되었습니다.');
        resetForm();
        onSuccess();
      } else {
        toast.error('등록에 실패했습니다.');
      }
    } catch {
      toast.error('등록 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  };

  const resetForm = () => {
    setTitle('');
    setContent('');
    setImages([]);
    setVideoType('link');
    setVideoUrl('');
    setVideoFile(null);
  };

  const handleClose = () => {
    resetForm();
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Music 등록</DialogTitle>
          <DialogDescription>새로운 음악을 등록하세요.</DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Title */}
          <div className="space-y-2">
            <Label htmlFor="title">제목 *</Label>
            <Input
              id="title"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="제목을 입력하세요"
            />
          </div>

          {/* Content */}
          <div className="space-y-2">
            <Label htmlFor="content">설명</Label>
            <Textarea
              id="content"
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder="설명을 입력하세요..."
              className="min-h-[100px]"
            />
          </div>

          {/* Video Input */}
          <div className="space-y-3">
            <Label>동영상</Label>
            <RadioGroup
              value={videoType}
              onValueChange={(value) => setVideoType(value as 'link' | 'upload')}
              className="flex gap-4"
            >
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="link" id="link" />
                <Label htmlFor="link" className="cursor-pointer flex items-center gap-1">
                  <Link className="h-4 w-4" />
                  링크
                </Label>
              </div>
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="upload" id="upload" />
                <Label htmlFor="upload" className="cursor-pointer flex items-center gap-1">
                  <Video className="h-4 w-4" />
                  업로드
                </Label>
              </div>
            </RadioGroup>

            {videoType === 'link' ? (
              <Input
                value={videoUrl}
                onChange={(e) => setVideoUrl(e.target.value)}
                placeholder="YouTube 또는 동영상 링크를 입력하세요"
              />
            ) : (
              <div>
                <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-dashed border-border bg-muted cursor-pointer hover:bg-muted/80 transition-colors">
                  <Video className="h-6 w-6 text-muted-foreground mb-1" />
                  <span className="text-sm text-muted-foreground">
                    {videoFile ? videoFile.name : '동영상 파일 선택'}
                  </span>
                  <input
                    type="file"
                    accept="video/*"
                    onChange={handleVideoFileChange}
                    className="hidden"
                  />
                </label>
              </div>
            )}
          </div>

          {/* Image Upload */}
          <div className="space-y-2">
            <Label>썸네일 이미지</Label>
            
            {images.length > 0 && (
              <div className="grid grid-cols-4 gap-2 mb-2">
                {images.map((img, index) => (
                  <div key={index} className="relative aspect-square bg-muted">
                    <Image
                      src={img.preview}
                      alt={`Preview ${index + 1}`}
                      fill
                      className="object-cover"
                    />
                    <Button
                      type="button"
                      variant="destructive"
                      size="icon"
                      className="absolute top-1 right-1 h-5 w-5"
                      onClick={() => handleRemoveImage(index)}
                    >
                      <X className="h-3 w-3" />
                    </Button>
                  </div>
                ))}
              </div>
            )}

            <label className="flex flex-col items-center justify-center w-full h-20 border-2 border-dashed border-border bg-muted cursor-pointer hover:bg-muted/80 transition-colors">
              <Plus className="h-5 w-5 text-muted-foreground mb-1" />
              <span className="text-sm text-muted-foreground">이미지 추가</span>
              <input
                type="file"
                accept="image/*"
                multiple
                onChange={handleImageChange}
                className="hidden"
              />
            </label>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button type="button" variant="outline" onClick={handleClose}>
              취소
            </Button>
            <Button type="submit" disabled={isLoading} className="flex items-center gap-2">
              <Upload className="h-4 w-4" />
              {isLoading ? '저장 중...' : '저장'}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}
